// ========================================================================
// APPROACH B: Generate a Presigned PUT URL for MinIO
// Then use a plain HTTP Request node (no auth) to upload
// ========================================================================
const crypto = require('crypto');

// MinIO configuration
const MINIO_ENDPOINT = '192.168.1.240';
const MINIO_PORT = '9000';
const MINIO_ACCESS_KEY = '[REDACTED_MINIO_ACCESS_KEY]';
const MINIO_SECRET_KEY = '[REDACTED_MINIO_SECRET_KEY]';
const REGION = 'us-east-1';
const BUCKET = $json.bucket || 'obsidian-vault';
const KEY = $json.fileKey;
const EXPIRES_IN = 3600; // 1 hour

// Helper: HMAC-SHA256
function hmac(key, data) {
  return crypto.createHmac('sha256', key).update(data).digest();
}

// Helper: SHA256 hex
function sha256hex(data) {
  return crypto.createHash('sha256').update(data).digest('hex');
}

// Build presigned URL using AWS Signature V4
const now = new Date();
const dateStamp = now.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';
const dateOnly = dateStamp.substring(0, 8);
const scope = `${dateOnly}/${REGION}/s3/aws4_request`;

// Canonical query string parameters (alphabetically sorted)
const queryParams = {
  'X-Amz-Algorithm': 'AWS4-HMAC-SHA256',
  'X-Amz-Credential': `${MINIO_ACCESS_KEY}/${scope}`,
  'X-Amz-Date': dateStamp,
  'X-Amz-Expires': String(EXPIRES_IN),
  'X-Amz-SignedHeaders': 'host'
};

const canonicalQueryString = Object.keys(queryParams)
  .sort()
  .map(k => `${encodeURIComponent(k)}=${encodeURIComponent(queryParams[k])}`)
  .join('&');

// Canonical request
const encodedKey = KEY.split('/').map(s => encodeURIComponent(s)).join('/');
const canonicalUri = `/${BUCKET}/${encodedKey}`;
const host = `${MINIO_ENDPOINT}:${MINIO_PORT}`;

const canonicalRequest = [
  'PUT',
  canonicalUri,
  canonicalQueryString,
  `host:${host}\n`,
  'host',
  'UNSIGNED-PAYLOAD'
].join('\n');

// String to sign
const stringToSign = [
  'AWS4-HMAC-SHA256',
  dateStamp,
  scope,
  sha256hex(canonicalRequest)
].join('\n');

// Signing key
const kDate = hmac(`AWS4${MINIO_SECRET_KEY}`, dateOnly);
const kRegion = hmac(kDate, REGION);
const kService = hmac(kRegion, 's3');
const kSigning = hmac(kService, 'aws4_request');

// Signature
const signature = crypto.createHmac('sha256', kSigning).update(stringToSign).digest('hex');

// Build final presigned URL
const presignedUrl = `http://${host}${canonicalUri}?${canonicalQueryString}&X-Amz-Signature=${signature}`;

return [{ json: {
  presignedUrl,
  noteContent: $json.noteContent,
  fileKey: KEY,
  expiresIn: EXPIRES_IN
}}];

const response = $input.first().json;
