}

// ========================================================================
// APPROACH C: Full Code Node Upload (MOST RELIABLE)
// Complete AWS V4 signing + HTTP PUT in a single Code node.
// Zero dependency on n8n credential system.
// ========================================================================
const crypto = require('crypto');
const http = require('http');

// MinIO configuration
const MINIO_HOST = '192.168.1.240';
const MINIO_PORT = 9000;
const ACCESS_KEY = '[REDACTED_MINIO_ACCESS_KEY]';
const SECRET_KEY = '[REDACTED_MINIO_SECRET_KEY]';
const REGION = 'us-east-1';
const BUCKET = $json.bucket || 'obsidian-vault';
const KEY = $json.fileKey;
const CONTENT = $json.noteContent;

// ---- AWS V4 Signing Helpers ----
function hmac(key, data, encoding) {
  const h = crypto.createHmac('sha256', key).update(data, 'utf8');
  return encoding ? h.digest(encoding) : h.digest();
}

function sha256(data, encoding) {
  return crypto.createHash('sha256').update(data, 'utf8').digest(encoding || 'hex');
}

function getSignatureKey(key, dateStamp, regionName, serviceName) {
  const kDate = hmac('AWS4' + key, dateStamp);
  const kRegion = hmac(kDate, regionName);
  const kService = hmac(kRegion, serviceName);
  return hmac(kService, 'aws4_request');
}

// ---- Build the signed request ----
const now = new Date();
const amzDate = now.toISOString().replace(/[-:]/g, '').replace(/\.\d+Z$/, 'Z');
const dateStamp = amzDate.substring(0, 8);

const body = Buffer.from(CONTENT, 'utf-8');
const payloadHash = sha256(body, 'hex');

// Encode the key path (preserve /)
const encodedKey = KEY.split('/').map(s => encodeURIComponent(s)).join('/');
const canonicalUri = `/${BUCKET}/${encodedKey}`;
const host = `${MINIO_HOST}:${MINIO_PORT}`;

// Headers to sign
const headers = {
  'host': host,
  'content-type': 'text/markdown; charset=utf-8',
  'content-length': String(body.length),
  'x-amz-content-sha256': payloadHash,
  'x-amz-date': amzDate
};

// Canonical headers (sorted, lowercased)
const sortedHeaderKeys = Object.keys(headers).sort();
const canonicalHeaders = sortedHeaderKeys.map(k => `${k}:${headers[k]}`).join('\n') + '\n';
const signedHeaders = sortedHeaderKeys.join(';');

// Canonical request
const canonicalRequest = [
  'PUT',
  canonicalUri,
  '', // empty query string
  canonicalHeaders,
  signedHeaders,
  payloadHash
].join('\n');

// String to sign
const credentialScope = `${dateStamp}/${REGION}/s3/aws4_request`;
const stringToSign = [
  'AWS4-HMAC-SHA256',
  amzDate,
  credentialScope,
  sha256(canonicalRequest, 'hex')
].join('\n');

// Signing key and signature
const signingKey = getSignatureKey(SECRET_KEY, dateStamp, REGION, 's3');
const signature = hmac(signingKey, stringToSign, 'hex');

// Authorization header
const authHeader = `AWS4-HMAC-SHA256 Credential=${ACCESS_KEY}/${credentialScope}, SignedHeaders=${signedHeaders}, Signature=${signature}`;

// ---- Execute HTTP PUT ----
const result = await new Promise((resolve, reject) => {
  const options = {
    hostname: MINIO_HOST,
    port: MINIO_PORT,
    path: canonicalUri,
    method: 'PUT',
    headers: {
      ...headers,
      'Authorization': authHeader
    }
  };

  const req = http.request(options, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      resolve({
        statusCode: res.statusCode,
        headers: res.headers,
        body: data
      });
    });
  });

  req.on('error', (err) => reject(err));
  req.write(body);
  req.end();
});

if (result.statusCode < 200 || result.statusCode >= 300) {
  throw new Error(`MinIO upload failed [${result.statusCode}]: ${result.body}`);
}

return [{ json: {
  success: true,
  method: 'approach-c-code-node-full',
  statusCode: result.statusCode,
  etag: result.headers?.etag || 'unknown',
  fileKey: KEY,
  bucket: BUCKET,
  size: body.length
}}];

