const MINIO_HOST = '192.168.1.240';
const MINIO_PORT = 9000;
const ACCESS_KEY = '[REDACTED_MINIO_ACCESS_KEY]';
const SECRET_KEY = '[REDACTED_MINIO_SECRET_KEY]';
const REGION = 'us-east-1';

// Get the file key from upstream
const input = $input.first().json;
const BUCKET = input.bucket || 'obsidian-vault';
const KEY = input.fileKey || $('Mock Input (Replace Me)').first().json.fileKey;

function hmac(key, data, enc) {
  const h = crypto.createHmac('sha256', key).update(data, 'utf8');
  return enc ? h.digest(enc) : h.digest();
}
function sha256(data, enc) {
  return crypto.createHash('sha256').update(data, 'utf8').digest(enc || 'hex');
}
function getSignKey(key, ds, region, svc) {
  return hmac(hmac(hmac(hmac('AWS4' + key, ds), region), svc), 'aws4_request');
}

const now = new Date();
const amzDate = now.toISOString().replace(/[-:]/g, '').replace(/\.\d+Z$/, 'Z');
const dateStamp = amzDate.substring(0, 8);
const encodedKey = KEY.split('/').map(s => encodeURIComponent(s)).join('/');
const canonicalUri = `/${BUCKET}/${encodedKey}`;
const host = `${MINIO_HOST}:${MINIO_PORT}`;

const payloadHash = sha256('', 'hex');
const headers = {
  'host': host,
  'x-amz-content-sha256': payloadHash,
  'x-amz-date': amzDate
};
const sortedKeys = Object.keys(headers).sort();
const canonicalHeaders = sortedKeys.map(k => `${k}:${headers[k]}`).join('\n') + '\n';
const signedHeaders = sortedKeys.join(';');

const canonicalRequest = ['HEAD', canonicalUri, '', canonicalHeaders, signedHeaders, payloadHash].join('\n');
const scope = `${dateStamp}/${REGION}/s3/aws4_request`;
const stringToSign = ['AWS4-HMAC-SHA256', amzDate, scope, sha256(canonicalRequest, 'hex')].join('\n');
const signingKey = getSignKey(SECRET_KEY, dateStamp, REGION, 's3');
const signature = hmac(signingKey, stringToSign, 'hex');
const authHeader = `AWS4-HMAC-SHA256 Credential=${ACCESS_KEY}/${scope}, SignedHeaders=${signedHeaders}, Signature=${signature}`;

const result = await new Promise((resolve, reject) => {
  const req = http.request({
    hostname: MINIO_HOST,
    port: MINIO_PORT,
    path: canonicalUri,
    method: 'HEAD',
    headers: { ...headers, 'Authorization': authHeader }
  }, (res) => {
    resolve({ statusCode: res.statusCode, headers: res.headers });
  });
  req.on('error', reject);
  req.end();
});

if (result.statusCode === 200) {
  return [{ json: {
    verified: true,
    fileKey: KEY,
    bucket: BUCKET,
    size: parseInt(result.headers['content-length'] || '0'),
    etag: result.headers.etag,
    lastModified: result.headers['last-modified'],
    contentType: result.headers['content-type']
  }}];
} else {
  throw new Error(`Verification failed: HEAD returned ${result.statusCode} for ${KEY}`);
}
